import React, { useState, useEffect } from 'react';
import DisplayStockData from './Stock';
import './Stock.css'

function View() {
  const [symbols, setSymbols] = useState([]);
  const [stockData, setStockData] = useState([]);

  const handleAddSymbol = async symbol => {
    if (symbols.length < 6 && !symbols.includes(symbol)) {
      const response = await fetch(`http://127.0.0.1:8000/${symbol}/`);
      const data = await response.json();
      if (data.hasOwnProperty('error')) {
        alert(data.error);
        return;
      }
      setSymbols([...symbols, symbol]);
    } else {
      alert("Symbol already entered or maximum limit reached (6)");
    }
  };
  

  const handleRemoveSymbol = symbol => {
    setSymbols(symbols.filter(item => item !== symbol));
    setStockData(stockData.filter(item => item.symbol !== symbol));
  };  


  useEffect(() => {
    const fetchData = async () => {
      if (!symbols.length) {
        return;
      }
      const urls = symbols.map(symbol => `http://127.0.0.1:8000/${symbol}/`);
      const promises = urls.map(url => fetch(url).then(response => response.json()));
      const data = await Promise.all(promises);
      setStockData(data);
    };
    fetchData();
  }, [symbols]);

  useEffect(() => {
    let sockets = [];
    if (stockData.length) {
      stockData.forEach(data => {
        const socket = new WebSocket(`ws://127.0.0.1:8000/ws/stock/${data.symbol}/`);
        socket.onmessage = event => {
          const updatedData = JSON.parse(event.data);
          setStockData(prevData => prevData.map(item => (item.symbol === updatedData.symbol ? updatedData : item)));
        };
        sockets.push(socket);
      });
    }
    return () => {
      sockets.forEach(socket => socket.close());
    };
  }, [stockData]);

  return (
    <div className='grid'>
      <div className='logo'>
        logo
      </div>
      <div className='head'>
        HEAD
      </div>
      <div className='prof'>
        profile
      </div>
      <form
        onSubmit={event => {
          event.preventDefault();
          const symbol = event.target.symbol.value.toUpperCase();
          handleAddSymbol(symbol);
          event.target.symbol.value = '';
        }}
      ><div className='five'>
          <input type="text"  name="symbol" />
        <button type="submit" >Add Symbol</button>
      </div>
        
      </form>
      {symbols.length > 0 && (
        <p>
          {symbols.length} of 6 stocks selected &nbsp;
          <button onClick={() => {
            setSymbols([]);
            setStockData([]);
          }}>Clear All</button>
        </p>
      )}
      <div className="info-container">
        {stockData.map(data => (
          <div key={data.symbol} className="info">
            <DisplayStockData stockData={data} />
            {/* <button onClick={() => handleRemoveSymbol(data.symbol)}>&#10799;</button> */}
          </div>
        ))}
      </div>
    </div>
  );
}

export default View;





